// Получаем входные данные. Это может быть строка или массив строк.
const input = $json.message.text;

// Если данных нет, возвращаем null
if (!input) {
  return null;
}

// Преобразуем входные данные в единую строку для поиска.
// Если это массив, соединяем его элементы через пробел.
// Если это уже строка, оставляем как есть.
const textToSearch = Array.isArray(input) ? input.join(' ') : input;

// Список слов для поиска (маркеры)
const keywords = [
  'GigaChat',
  'Гигачат',
  'Giga',
  'Гига',
  '@gigachat_bot'
];

// Создаем регулярное выражение из списка слов.
// 'i' - флаг, делающий поиск нечувствительным к регистру (найдет и "Giga", и "giga", и "GIGA").
const regex = new RegExp(keywords.join('|'), 'i');

// Ищем совпадение в тексте
const match = textToSearch.match(regex);

// Если совпадение найдено (match не равен null)
if (match) {
  // match[0] содержит именно то слово, которое было найдено в тексте
  const foundWord = match[0];

  // Возвращаем результат в формате n8n
  return [{
    json: {
      textmarker: foundWord
    }
  }];
}

// Если ни одно из слов не найдено, возвращаем null
return [{
  json: {
    textmarker: null
  }
}];

// Получаем исходный текст
const inputText = $('Telegram Trigger').first().json.message.text;

// Создаем новую строку, повторяя текст два раза через подчеркивание
const resultText = `${inputText} ${inputText}`;

// Возвращаем результат в одном item
return [{
  json: {
    text: resultText
  }
}];

