const input = $input.first().json;
const text = $('Calendar').first().json.agent_response;

if (typeof text !== 'string') {
  return [{ json: { error: 'agent_response is not a string', raw: input } }];
}

// --------------------------------------------------
// 1. Если таблицы нет — просто возвращаем текст
// --------------------------------------------------
if (!text.includes('|')) {
  return [{ json: { response: text } }];
}

// --------------------------------------------------
// 2. Парсинг Markdown-таблицы
// --------------------------------------------------
const lines = text.split('\n').map(l => l.trim());

// строки таблицы: начинаются с |
const tableLines = lines.filter(l => l.startsWith('|'));

if (tableLines.length < 3) {
  // таблица некорректна — безопасный fallback
  return [{ json: { response: text } }];
}

// пропускаем заголовок и разделитель
const dataRows = tableLines.slice(2);

const events = [];

for (const row of dataRows) {
  const cols = row
    .split('|')
    .map(c => c.trim())
    .filter(Boolean);

  if (cols.length < 3) continue;

  const [dateRaw, timeRaw, nameRaw] = cols;

  events.push({
    dateRaw,
    timeRaw,
    name: nameRaw
  });
}

// --------------------------------------------------
// 3. Агрегация дубликатов (как в myownassist.txt)
// --------------------------------------------------
const keyOf = e => `${e.dateRaw}|${e.timeRaw}|${e.name.toLowerCase()}`;

const grouped = {};
for (const e of events) {
  const key = keyOf(e);
  grouped[key] = grouped[key] || [];
  grouped[key].push(e);
}

// --------------------------------------------------
// 4. Формирование вывода в стиле formatTelegramResponse
// --------------------------------------------------
const output = [];
output.push('📅 Найдено событий за период');

let hasDuplicates = false;
const now = new Date();

for (const key of Object.keys(grouped)) {
  const group = grouped[key];
  const e = group[0];

  let status = '⏱️';

  // попытка определить "прошло / нет"
  const timeMatch = e.timeRaw.match(/(\d{1,2}):(\d{2})/);
  if (timeMatch) {
    const [h, m] = timeMatch.slice(1).map(Number);
    const dateMatch = e.dateRaw.match(/(\d{1,2})\s+([а-я]+)/i);
    if (dateMatch) {
      const day = Number(dateMatch[1]);
      const eventDate = new Date(now.getFullYear(), now.getMonth(), day, h, m);
      if (eventDate < now) status = '✅';
    }
  }

  if (group.length > 1) {
    status = `🔄 ${group.length} дубликата`;
    hasDuplicates = true;
  }

  output.push(
    `• ${e.dateRaw}, ${e.timeRaw} — ${e.name}, ${status}`
  );
}

output.push('───');

if (hasDuplicates) {
  output.push(
    '⚠️ Чтобы изменить/удалить дубликаты событий, пришлите их название, время или ID.'
  );
}

return [{
  json: {
    response: output.join('\n')
  }
}];

