const ALLOWED_TAGS = ['b','i','u','s','code','pre','a'];   // whitelist

/* ───── Helpers ───── */

// базовое экранирование
const escapeHTML = s => s
  .replace(/&/g,'&amp;')
  .replace(/</g,'&lt;')
  .replace(/>/g,'&gt;')
  .replace(/"/g,'&quot;')
  .replace(/'/g,'&#39;');

// разрешаем только whitelisted-теги
function whitelistTags(str){
