      const id = placeholders.push(m) - 1;
      return `§§${id}§§`;
    }
    return m;          // остальные теги будут экранированы
  });
  // 2) глобально экранируем
  let safe = escapeHTML(masked);
  // 3) возвращаем whitelisted-теги
  placeholders.forEach((tag,i)=>{
    safe = safe.replace(`§§${i}§§`, tag);
  });
